from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Any

@dataclass
class HookResult:
    data: Any
    stop_propagation: bool = False  # if True, no further plugins process this hook

class Plugin(ABC):
    @property
    @abstractmethod
    def name(self) -> str:
        ...
    @property
    def version(self) -> str:
        return '1.0.0'
    def on_activate(self) -> None:
        pass
    def on_deactivate(self) -> None:
        pass

