def test_register_and_list():
    class MyPlugin(Plugin):
        @property
        def name(self): return 'my_plugin'
    pm = PluginManager()
    pm.register(MyPlugin())
    assert 'my_plugin' in pm.list_plugins()

def test_enable_disable():
    class MyPlugin(Plugin):
        @property
        def name(self): return 'test'
    pm = PluginManager()
    pm.register(MyPlugin())
    pm.enable('test')
    assert pm.is_enabled('test') == True
    pm.disable('test')
    assert pm.is_enabled('test') == False

def test_dispatch_hook():
    class UpperPlugin(Plugin):
        @property
        def name(self): return 'upper'
        def process_text(self, data):
            return HookResult(data=data.upper())
    pm = PluginManager()
    pm.register(UpperPlugin())
    pm.enable('upper')
    result = pm.dispatch_hook('process_text', 'hello')
    assert result == 'HELLO'

def test_pipeline_order():
    class AddExclaim(Plugin):
        @property
        def name(self): return 'exclaim'
        def transform(self, data):
            return HookResult(data=data + '!')
    class AddQuestion(Plugin):
        @property
        def name(self): return 'question'
        def transform(self, data):
            return HookResult(data=data + '?')
    pm = PluginManager()
    pm.register(AddExclaim())
    pm.register(AddQuestion())
    pm.enable('exclaim')
    pm.enable('question')
    result = pm.dispatch_hook('transform', 'hi')
    assert result == 'hi!?'

def test_stop_propagation():
    class Stopper(Plugin):
        @property
        def name(self): return 'stopper'
        def process(self, data):
            return HookResult(data='stopped', stop_propagation=True)
    class Never(Plugin):
        @property
        def name(self): return 'never'
        def process(self, data):
            return HookResult(data='should not reach')
    pm = PluginManager()
    pm.register(Stopper())
    pm.register(Never())
    pm.enable('stopper')
    pm.enable('never')
    result = pm.dispatch_hook('process', 'data')
    assert result == 'stopped'

def test_disabled_plugin_skipped():
    class MyPlugin(Plugin):
        @property
        def name(self): return 'skipped'
        def hook(self, data):
            return HookResult(data='modified')
    pm = PluginManager()
    pm.register(MyPlugin())
    result = pm.dispatch_hook('hook', 'original')
    assert result == 'original'

def test_unregister():
    class MyPlugin(Plugin):
        @property
        def name(self): return 'temp'
    pm = PluginManager()
    pm.register(MyPlugin())
    assert pm.unregister('temp') == True
    assert pm.unregister('temp') == False
    assert pm.list_plugins() == []

def test_lifecycle_callbacks():
    log = []
    class LifecyclePlugin(Plugin):
        @property
        def name(self): return 'lifecycle'
        def on_activate(self):
            log.append('activated')
        def on_deactivate(self):
            log.append('deactivated')
    pm = PluginManager()
    pm.register(LifecyclePlugin())
    pm.enable('lifecycle')
    pm.disable('lifecycle')
    assert log == ['activated', 'deactivated']

def test_get_plugin():
    class MyPlugin(Plugin):
        @property
        def name(self): return 'finder'
    pm = PluginManager()
    p = MyPlugin()
    pm.register(p)
    assert pm.get_plugin('finder') is p
    assert pm.get_plugin('nonexistent') is None
